import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Weather icon mapping based on condition
// Weather icon mapping based on condition (case-insensitive)
const CONDITION_ICONS: Record<string, string> = {
  'sunny': '☀️',
  'cloudy': '☁️',
  'rainy': '🌧️',
  'snowy': '❄️',
  'windy': '💨',
  'clear': '🌙',
  'partly cloudy': '⛅',
  'partly_cloudy': '⛅',
  'partlycloudy': '⛅',
  'thunderstorm': '⛈️',
  'foggy': '🌫️',
  'hail': '🧊',
  'drizzle': '🌦️',
  'sleet': '🌨️',
  'overcast': '☁️',
};

function useComponent(props: Props) {
  // no state needed — all data comes from props

  return {};
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current Weather
          </Text>
        </Stack>

        {/* MAIN WEATHER CARD */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={24}>
            {/* Temperature & Condition Section */}
            <Stack direction="horizontal" align="center" gap={24}>
              {/* Weather Icon */}
              <Box>
                <Text size="4xl">
                  {CONDITION_ICONS[props.condition?.toLowerCase() || ''] || '🌤️'}
                </Text>
              </Box>

              {/* Temperature & Condition */}
              <Stack gap={8}>
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.temperature}°{props.unit}
                </Text>
                <Text size="xl" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {props.condition}
                </Text>
              </Stack>

              <Spacer size="flex" />
            </Stack>

            <Divider orientation="horizontal" margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

            {/* Humidity & Wind Speed */}
            <Stack direction="horizontal" gap={16} justify="between">
              {/* Humidity */}
              <Stack gap={4} align="center" justify="center" direction="horizontal">
                <Icon name="droplets" size={20} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Stack gap={2}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Humidity
                  </Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {props.humidity}%
                  </Text>
                </Stack>
              </Stack>

              {/* Wind Speed */}
              <Stack gap={4} align="center" justify="center" direction="horizontal">
                <Icon name="wind" size={20} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Stack gap={2}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Wind Speed
                  </Text>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    {props.windSpeed} m/s
                  </Text>
                </Stack>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST */}
        <Stack gap={12}>
          <Heading level={3}>5-Day Forecast</Heading>
           <Stack direction="horizontal" gap={12}>
             {(props.forecast ?? []).map((day, index) => (
              <Card
                key={index}
                shadow="sm"
                padding={16}
                radius="md"
                border
                style={{ flex: '1 1 140px', minWidth: '140px' }}
              >
                <Stack gap={8} align="center" justify="center">
                  <Text variant="label" align="center" color="var(--ggui-color-onSurface, #18181b)">
                     {day?.day || `Day ${index + 1}`}
                  </Text>

                   <Text size="2xl">
                       {day?.icon || '🌤️'}
                   </Text>

                  <Stack direction="horizontal" gap={4} justify="center" align="center">
                     <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                       {typeof day?.high === 'number' ? `${day.high}°${props.unit}` : '-'}
                     </Text>
                     <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                       {typeof day?.low === 'number' ? `${day.low}°${props.unit}` : '-'}
                     </Text>
                  </Stack>
                </Stack>
              </Card>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Survey form state shape
interface SurveyState {
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
}

// Email validation helper
const isValidEmail = (email: string): boolean => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

// Get satisfaction label from rating number
const getSatisfactionLabel = (rating: number, labels: string[]): string => {
  return labels[rating - 1] || `Rating ${rating}`;
};

function useComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [survey, setSurvey] = useState<SurveyState>({
    name: '',
    email: '',
    satisfaction: 0,
    features: [],
    comments: '',
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  // Validation for step 1
  const isStep1Valid = useMemo(() => {
    const nameValid = survey.name.trim().length > 0;
    const emailValid = isValidEmail(survey.email);
    return nameValid && emailValid;
  }, [survey.name, survey.email]);

  // Handle step 1 field changes
  const handleStep1Change = useCallback((field: 'name' | 'email', value: string) => {
    setSurvey(prev => ({ ...prev, [field]: value }));
    // Clear errors on change
    if (field === 'name' && value.trim().length > 0) setErrors(e => ({ ...e, name: '' }));
    if (field === 'email' && isValidEmail(value)) setErrors(e => ({ ...e, email: '' }));
  }, []);

  // Handle step 2: satisfaction selection
  const handleSatisfactionChange = useCallback((value: string) => {
    setSurvey(prev => ({ ...prev, satisfaction: parseInt(value, 10) }));
  }, []);

  // Handle step 3: feature selection
  const handleFeatureToggle = useCallback((feature: string) => {
    setSurvey(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature],
    }));
  }, []);

  // Handle step 4: comments
  const handleCommentsChange = useCallback((value: string) => {
    if (value.length <= 500) setSurvey(prev => ({ ...prev, comments: value }));
  }, []);

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) {
      const newErrors = { name: '', email: '' };
      if (survey.name.trim().length === 0) newErrors.name = 'Name is required';
      if (!isValidEmail(survey.email)) newErrors.email = 'Valid email is required';
      setErrors(newErrors);
      return;
    }
      if (currentStep < 4) setCurrentStep(currentStep + 1); else if (currentStep === 4) setCurrentStep(5); else setCurrentStep(currentStep + 1);
  }, [currentStep, survey.name, survey.email, isStep1Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    submit({
      name: survey.name,
      email: survey.email,
      satisfaction: survey.satisfaction,
      features: survey.features,
      comments: survey.comments,
    });
  }, [survey, submit]);

    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit');

  return { currentStep, survey, errors, isStep1Valid, handleStep1Change, handleSatisfactionChange, handleFeatureToggle, handleCommentsChange, handleNext, handleBack, handleSubmit, submit };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const { currentStep, survey, errors, isStep1Valid, handleStep1Change, handleSatisfactionChange, handleFeatureToggle, handleCommentsChange, handleNext, handleBack, handleSubmit } = state;

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        {/* PROGRESS BAR */}
        <Stack gap={8}>
          <Heading level={2}>Survey Form</Heading>
           <Progress value={currentStep} max={5} variant="default" showLabel />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {currentStep} of 5
            </Text>
        </Stack>

        {/* STEP 1: NAME & EMAIL */}
        {currentStep === 1 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Full Name"
                placeholder="Enter your name"
                value={survey.name}
                onChange={(value) => handleStep1Change('name', value)}
                error={errors.name}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="Enter your email"
                value={survey.email}
                onChange={(value) => handleStep1Change('email', value)}
                error={errors.email}
                required
              />
            </Stack>
          </Card>
        )}

        {/* STEP 2: SATISFACTION RATING */}
        {currentStep === 2 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={survey.satisfaction.toString()}
                onChange={handleSatisfactionChange}
                options={(props.satisfactionLabels || []).map((label, idx) => ({
                  value: (idx + 1).toString(),
                  label: label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}


        {/* STEP 3: FEATURE INTERESTS */}
        {currentStep === 3 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Features of Interest</Heading>
              <Stack gap={8}>
                {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={survey.features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 4: COMMENTS */}
        {currentStep === 4 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional feedback (optional)"
                value={survey.comments}
                onChange={handleCommentsChange}
                maxLength={500}
                showCount
                rows={6}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {survey.comments.length}/500 characters used
              </Text>
            </Stack>
          </Card>
        )}

        {/* STEP 5: FINAL REVIEW */}
        {currentStep === 5 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap={12}>
                <Stack gap={4}>
                  <Text variant="label">Full Name</Text>
                  <Text>{survey.name}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Email Address</Text>
                  <Text>{survey.email}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Satisfaction Rating</Text>
                  <Text>{(props.satisfactionLabels && props.satisfactionLabels.length > 0) ? getSatisfactionLabel(survey.satisfaction, props.satisfactionLabels) : `Rating ${survey.satisfaction}`}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Features of Interest</Text>
                  <Stack gap={4}>
                    {survey.features.length > 0 ? (
                      survey.features.map((feature) => (
                        <Badge key={feature} variant="primary">{feature}</Badge>
                      ))
                    ) : (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">None selected</Text>
                    )}
                  </Stack>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Comments</Text>
                  <Text>{survey.comments || '(No comments provided)'}</Text>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}
        {/* NAVIGATION BUTTONS */}
        <Row gap={8} justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 5 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={currentStep === 1 && !isStep1Valid}
            >
              Next
            </Button>
          )}
          {currentStep === 5 && (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
      </Button>
           </Row>
       </Stack>
     </Container>
   );
 }

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// if you have local types or interfaces, place them here
interface Task extends NonNullable<Props['tasks'][0]> {}
interface Column extends NonNullable<Props['columns'][0]> {}

// if you have constants, config, or mappings, place them here
const PRIORITY_COLORS: Record<string, string> = {
  low: 'var(--ggui-color-success-600, #16a34a)',
  medium: 'var(--ggui-color-warning-600, #d97706)',
  high: 'var(--ggui-color-error-600, #dc2626)',
};

// if you have reusable UI pieces, extract them as small functions here
interface TaskCardProps {
  task: Task;
  onMove: (taskId: string, column: string) => void;
  columns: Column[];
}

function TaskCard({ task, onMove, columns }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');

  const handleSaveEdit = useCallback(() => {
    if (editTitle.trim()) {
      setIsEditing(false);
    }
  }, [editTitle]);

  return (
    <Card padding={12} shadow="sm" border={true} radius="md" as={Hoverable} hoverStyle={{ background: 'var(--ggui-color-primary-50, #f0f9ff)' }}>
      <Stack gap={8}>
        {isEditing ? (
          <Input
            label="Task title"
            value={editTitle}
            onChange={setEditTitle}
            onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) => {
              if (e.key === 'Enter') handleSaveEdit();
              if (e.key === 'Escape') setIsEditing(false);
            }}
          />
        ) : (
          <Text
            variant="body"
            weight="semibold"
            as={Clickable}
            onClick={() => setIsEditing(true)}
            style={{ cursor: 'pointer' }}
          >
             {task.title || 'Untitled'}
          </Text>
        )}

        <Stack direction="horizontal" gap={8} align="center">
          {task.priority && (
            <Badge
              variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'}
              size="sm"
            >
              {task.priority}
            </Badge>
          )}
          {task.assignee && <Avatar name={task.assignee} size="xs" />}
        </Stack>

        {task.dueDate && (
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Due: {new Date(task.dueDate).toLocaleDateString()}
          </Text>
        )}

        <Dropdown
          trigger={<Button variant="ghost" size="xs">Move</Button>}
           options={columns.filter(col => col.id && col.name).map(col => ({ value: col.id!, label: col.name! }))}
          value={task.column || ''}
          onChange={(colId) => onMove(task.id || '', colId)}
          placement="bottom-end"
        />
      </Stack>
    </Card>
  );
}

interface ColumnCardProps {
  column: Column;
  tasks: Task[];
  onMoveTask: (taskId: string, column: string) => void;
  onAddTask: (title: string, priority: string) => void;
  columns: Column[];
}

function ColumnCard({ column, tasks, onMoveTask, onAddTask, columns }: ColumnCardProps) {
  const [showAddForm, setShowAddForm] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');

  const columnTasks = (tasks || []).filter(t => t.column === column.id);

  const handleAddTask = useCallback(() => {
    if (newTaskTitle.trim()) {
      onAddTask(newTaskTitle, newTaskPriority);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddForm(false);
    }
  }, [newTaskTitle, newTaskPriority, onAddTask]);

  return (
    <Card padding={16} shadow="md" border={true} radius="lg" style={{ minWidth: '280px', maxHeight: '600px', overflowY: 'auto' }}>
       <Stack gap={12}>
         <Stack direction="horizontal" justify="between" align="center">
           <Heading level={4} style={{ margin: 0 }}>{column.name || 'Unnamed'}</Heading>
           <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
         </Stack>

         <Divider margin={4} />

         <Box style={{ flex: 1, overflowY: 'auto' }}>
           <Stack gap={8}>
             {columnTasks.map(task => (
                <TaskCard key={task.id || `task-${Math.random()}`} task={task} onMove={onMoveTask} columns={columns} />
             ))}
           </Stack>
         </Box>

        {showAddForm ? (
           <Box paddingX={12} paddingY={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
             <Stack gap={8}>
               <Input
                 label="Task title"
                 placeholder="Enter task title..."
                 value={newTaskTitle}
                 onChange={setNewTaskTitle}
               />
               <Select
                 label="Priority"
                 value={newTaskPriority}
                 onChange={setNewTaskPriority}
                 options={[
                   { value: 'low', label: 'Low' },
                   { value: 'medium', label: 'Medium' },
                   { value: 'high', label: 'High' },
                 ]}
               />
               <Stack direction="horizontal" gap={8} justify="end">
                 <Button variant="ghost" size="sm" onClick={() => setShowAddForm(false)}>Cancel</Button>
                 <Button variant="primary" size="sm" onClick={handleAddTask}>Add</Button>
               </Stack>
             </Stack>
           </Box>
        ) : (
          <Button
            variant="secondary"
            size="sm"
            fullWidth
            onClick={() => setShowAddForm(true)}
          >
            + Add Task
          </Button>
        )}
      </Stack>
