function useComponent(props: Props) {
  const [localTasks, setLocalTasks] = useState<Task[]>(props.tasks || []);

  useEffect(() => {
    if (props.tasks) setLocalTasks(props.tasks);
  }, [props.tasks]);

  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter(t => t.column === 'done').length;

  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    setLocalTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
  }, [taskUpdate]);

  const handleAddTask = useCallback((title: string, priority: string) => {
    const newTaskId = `task-${Date.now()}`;
    const newTask: Task = { id: newTaskId, title, priority: priority as 'low' | 'medium' | 'high', column: 'todo' };
    taskUpdate({ action: 'create', taskId: newTaskId, data: { column: 'todo' } });
    setLocalTasks(prev => [...prev, newTask]);
  }, [taskUpdate]);

  // Actions — fire-and-forget to agent
  // Streams — real-time from agent (.latest, .all)

  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  useEffect(() => {
    if (taskChanged.latest) {
      const event = taskChanged.latest;
      if (event.action === 'create' && event.task) {
        setLocalTasks(prev => [...prev, event.task as Task]);
      } else if (event.action === 'move' && event.task) {
        setLocalTasks(prev => prev.map(t => t.id === event.task?.id ? { ...t, column: event.task.column } : t));
      } else if (event.action === 'edit' && event.task) {
        setLocalTasks(prev => prev.map(t => t.id === event.task?.id ? { ...event.task as Task } : t));
      } else if (event.action === 'delete' && event.task?.id) {
        setLocalTasks(prev => prev.filter(t => t.id !== event.task?.id));
      }
    }
  }, [taskChanged.latest]);

  return { localTasks, totalTasks, completedTasks, handleMoveTask, handleAddTask };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
