         </Stack>
       </Card>

        {/* KANBAN BOARD */}
        <Stack direction="horizontal" gap={16} style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
           {(props.columns || []).map(column => (
