  'actinide': { bg: 'var(--ggui-color-error-50, #fef2f2)', text: 'var(--ggui-color-error-800, #991b1b)' },
};

// Get color for a category with fallback
function getCategoryColor(category?: string) {
  if (!category) return { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurface, #18181b)' };
  return categoryColors[category.toLowerCase()] || categoryColors['metal'];
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // Filter elements by name or symbol
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  const handleElementClick = useCallback((element: ElementData) => {
    setSelectedElement(element);
  }, []);

  return { searchQuery, setSearchQuery, selectedElement, setSelectedElement, filteredElements, categories, handleElementClick };
}


