// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Type for grouped messages
interface MessageGroup {
  sender: string;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

// Group consecutive messages by same sender
function groupConsecutiveMessages(messages: Array<{ sender?: string; text?: string; timestamp?: string }>): MessageGroup[] {
  if (messages.length === 0) return [];
  const groups: MessageGroup[] = [];
  let currentGroup: MessageGroup | null = null;
  for (const msg of messages) {
    const sender = msg.sender || 'Unknown';
    if (!currentGroup || currentGroup.sender !== sender) {
      currentGroup = { sender, messages: [msg] };
      groups.push(currentGroup);
    } else {
      currentGroup.messages.push(msg);
    }
  }
  return groups;
}

function useComponent(props: Props) {
  // State: messages from props + stream, typing status, input field
  const [messages, setMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const [processedMessageIds, setProcessedMessageIds] = useState(new Set<string>());
  const [typingTimeoutId, setTypingTimeoutId] = useState<NodeJS.Timeout | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Wire hooks for real-time messaging
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  // Append new messages from stream with deduplication
  const handleNewMessage = useCallback(() => {
    if (message.latest) {
      const msgId = `${message.latest.sender}-${message.latest.timestamp}`;
      setProcessedMessageIds(prev => {
        if (prev.has(msgId)) return prev;
        const updated = new Set(prev);
        updated.add(msgId);
        setMessages(msgs => [...msgs, message.latest!]);
        return updated;
      });
    }
  }, [message.latest]);

  // Update typing indicator from stream with auto-clear timeout
  const handleTypingUpdate = useCallback(() => {
    if (typing.latest) {
      const { sender, active } = typing.latest;
      if (typingTimeoutId) clearTimeout(typingTimeoutId);
      if (active && sender) {
        setTypingUser(sender);
        const timeoutId = setTimeout(() => {
          setTypingUser(null);
          setTypingTimeoutId(null);
        }, 4000);
        setTypingTimeoutId(timeoutId);
      } else {
        setTypingUser(null);
        setTypingTimeoutId(null);
      }
    }
  }, [typing.latest, typingTimeoutId]);

  // Effect: handle new messages on mount and when stream updates
  useEffect(() => {
    handleNewMessage();
  }, [message.latest, handleNewMessage]);

  // Effect: handle typing updates
  useEffect(() => {
    handleTypingUpdate();
  }, [typing.latest, handleTypingUpdate]);

  // Effect: auto-scroll to bottom on new messages
  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  // Cleanup typing timeout on unmount
  useEffect(() => {
    return () => {
      if (typingTimeoutId) clearTimeout(typingTimeoutId);
    };
  }, [typingTimeoutId]);

  // Send message handler: add sent message to state immediately, then send action
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const payload: ActionSendMessagePayload = {
        text: inputValue,
        timestamp: new Date().toISOString(),
      };
      // Append sent message to messages list immediately
      setMessages(prev => [...prev, { sender: props.currentUser, text: inputValue, timestamp: payload.timestamp }]);
      sendMessage(payload);
      setInputValue('');
    }
  }, [inputValue, sendMessage, props.currentUser]);

  // Handle Enter key to send
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  return { messages, inputValue, setInputValue, typingUser, handleSendMessage, handleKeyDown, messagesEndRef };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={16}>
        {/* HEADER: Chat title + participant count badge */}
        <Stack gap={8} align="center" direction="horizontal" justify="between">
          <Heading level={2}>{props.title}</Heading>
          <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
        </Stack>

        {/* MESSAGE LIST: Scrollable area with messages */}
        <Card
          shadow="md"
          padding={16}
          radius="lg"
          style={{
            minHeight: '400px',
            maxHeight: '500px',
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          {state.messages.length === 0 ? (
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center" style={{ margin: 'auto' }}>
              No messages yet. Start a conversation!
            </Text>
          ) : (
            groupConsecutiveMessages(state.messages).map((group, groupIdx) => {
              const isCurrent = group.sender === props.currentUser;
              const groupKey = `${group.sender}-${groupIdx}`;
              return (
                <Stack
                  key={groupKey}
                  gap={8}
                  align={isCurrent ? 'end' : 'start'}
                  style={isCurrent ? { marginLeft: 'auto' } : {}}
                >
                  {/* Sender name and avatar (only for non-current users) */}
                  <Stack direction="horizontal" align="start" gap={8}>
                    {!isCurrent && (
                      <Avatar
                        name={group.sender}
                        size="sm"
                        shape="circle"
                      />
                    )}
                    <Stack gap={4}>
                      {/* Render all messages in this group */}
                      {group.messages.map((msg, msgIdx) => {
                        const msgKey = `${msg.sender}-${msg.timestamp}-${msgIdx}`;
                        return (
                          <Box
                            key={msgKey}
                            background={isCurrent ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                            padding={12}
                            borderRadius="var(--ggui-shape-radius-md, 8px)"
                            style={{ maxWidth: '70%', wordWrap: 'break-word' }}
                          >
                            <Text
                              variant="body"
                              color={isCurrent ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                            >
                              {msg.text}
                            </Text>
                            <Text
                              variant="caption"
                              color={isCurrent ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                              size="xs"
                              align="right"
                              style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
                            >
                              {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                            </Text>
                          </Box>
                        );
                      })}
                    </Stack>
                  </Stack>
                </Stack>
              );
            })
          )}

          {/* Typing indicator */}
          {state.typingUser && (
            <Stack direction="horizontal" align="end" gap={8}>
              <Avatar
                name={state.typingUser}
                size="sm"
                shape="circle"
              />
              <Box
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                padding={12}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Text
                  variant="bodySmall"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {state.typingUser} is typing
                  <span style={{ animation: 'blink 1.4s infinite', marginLeft: 'var(--ggui-spacing-1, 4px)' }}>…</span>
                </Text>
              </Box>
            </Stack>
          )}
          {/* Invisible scroll anchor */}
          <div ref={state.messagesEndRef} />
        </Card>

        {/* INPUT AREA: TextArea + Send button */}
        <Stack gap={12}>
          <TextArea
            label="Message"
            placeholder="Type your message here... (Shift+Enter for newline)"
            value={state.inputValue}
            onChange={state.setInputValue}
            onKeyDown={state.handleKeyDown}
            rows={3}
          />
          <Button
            variant="primary"
            onClick={state.handleSendMessage}
            disabled={!state.inputValue.trim()}
            fullWidth
          >
            Send
          </Button>
        </Stack>
      </Stack>
      <style>{`
        @keyframes blink {
          0%, 20%, 50%, 80%, 100% { opacity: 1; }
          40% { opacity: 0; }
          60% { opacity: 0; }
        }
      `}</style>
    </Container>
  );
}

