// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion, MotionKeyframes } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Helper function to determine color based on change
// Helper function to determine color based on change
function getChangeColor(changePercent?: number): string {
  if (changePercent === undefined || changePercent === 0) return 'var(--ggui-color-onSurface, #18181b)';
  return changePercent > 0 ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)';
}

// Helper function to get border color based on change
function getChangeBorderColor(changePercent?: number): string {
  if (changePercent === undefined || changePercent === 0) return 'var(--ggui-color-outline, #d4d4d8)';
  return changePercent > 0 ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)';
}

// Stock card component
interface StockCardProps {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
  isHighlighted?: boolean;
}

function StockCard({ symbol, name, price, change, changePercent, isHighlighted }: StockCardProps) {
  const changeColor = getChangeColor(changePercent);
  const borderColor = getChangeBorderColor(changePercent);
  const arrowIcon = changePercent !== undefined && changePercent > 0 ? '▲' : '▼';

  return (
    <Card
      shadow="md"
      padding={16}
      border={true}
      radius="lg"
      style={{
        borderColor: borderColor,
        animation: isHighlighted ? 'ggui-slideInUp 300ms ease-out forwards' : 'none',
        transition: 'all 200ms ease-in-out',
      }}
    >
      <Stack gap={12}>
        <Text variant="label" weight="bold" size="xl" color="var(--ggui-color-onSurface, #18181b)">
          {symbol || 'N/A'}
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {name || ''}
        </Text>
        <Divider margin={8} />
        <Text variant="body" weight="semibold" size="2xl" color="var(--ggui-color-onSurface, #18181b)">
          ${price ? price.toFixed(2) : '0.00'}
        </Text>
        <Stack direction="horizontal" gap={8} align="center">
          <Text variant="body" color={changeColor} weight="semibold">
            {change !== undefined && change >= 0 ? '+' : ''}{change?.toFixed(2) || '0.00'}
          </Text>
          <Text variant="body" color={changeColor} weight="semibold">
            <span style={{ marginRight: 'var(--ggui-spacing-1, 4px)' }}>{arrowIcon}</span>
            {changePercent?.toFixed(2) || '0.00'}%
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
}

function useComponent(props: Props) {
  // Merge initial stocks with stream updates
  const [displayStocks, setDisplayStocks] = useState(props.stocks || []);
  const [lastUpdatedSymbol, setLastUpdatedSymbol] = useState<string | null>(null);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<Date>(new Date());

  // Update stocks when props change
  useEffect(() => {
    if (props.stocks && props.stocks.length > 0) {
      setDisplayStocks(props.stocks);
      setLastUpdatedTime(new Date());
    }
  }, [props.stocks]);

  // Subscribe to stream updates and merge with initial stocks
  const priceUpdateStream = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatusStream = useStream<StreamMarketStatus>('marketStatus');

  // Update specific stock prices when stream events arrive
  useEffect(() => {
    if (!priceUpdateStream.latest?.symbol) return;
    const update = priceUpdateStream.latest;
    try {
      setDisplayStocks((prev) => {
        if (!Array.isArray(prev)) return prev || [];
        return prev.map((stock) =>
          stock.symbol === update.symbol
            ? { ...stock, price: update.price, change: update.change, changePercent: update.changePercent }
            : stock
        );
      });
      setLastUpdatedSymbol(update.symbol || null);
      setLastUpdatedTime(new Date());
    } catch (error) {
      console.error('Error processing price update:', error);
    }
  }, [priceUpdateStream.latest]);


  return { displayStocks, lastUpdatedSymbol, lastUpdatedTime, priceUpdateStream, marketStatusStream };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  // Format last updated time with real-time updates
  const [displayTime, setDisplayTime] = useState<string>(state.lastUpdatedTime.toLocaleTimeString());

  useEffect(() => {
    setDisplayTime(state.lastUpdatedTime.toLocaleTimeString());
  }, [state.lastUpdatedTime]);

  // Show loading state if no stocks
  const hasStocks = Array.isArray(state.displayStocks) && state.displayStocks.length > 0;

  return (
    <Container maxWidth="xl" padding={24}>
      <MotionKeyframes />
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {displayTime}
              </Text>
            </Stack>
          </Stack>
        </Stack>

        {/* LOADING STATE */}
        {!hasStocks && (
          <Box padding={48} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12}>
            <Stack gap={16} align="center" justify="center">
              <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks to display
              </Text>
            </Stack>
          </Box>
        )}

        {/* STOCK GRID */}
        {hasStocks && (
          <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={16}>
            {state.displayStocks.map((stock) => (
              <StockCard
                key={stock.symbol}
                symbol={stock.symbol}
                name={stock.name}
                price={stock.price}
                change={stock.change}
                changePercent={stock.changePercent}
                isHighlighted={state.lastUpdatedSymbol === stock.symbol}
              />
            ))}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

