// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream, useAgentTool, useClientTool } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };




// Local types for step management
type Step = 1 | 2 | 3;
interface FormData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: 'light' | 'dark';
}

// Email validation helper
const isValidEmail = (email: string): boolean => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
};

function useComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState<Step>(1);
  const [formData, setFormData] = useState<FormData>(() => ({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions?.[0] || '',
    role: props.initialProfile.role || props.roleOptions?.[0] || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: (props.initialProfile.theme as 'light' | 'dark') || 'light',
  }));

  // Validation for step 1
  const isStep1Valid = useMemo(() => {
    return formData.name.trim() !== '' && isValidEmail(formData.email) && formData.avatar !== '';
  }, [formData.name, formData.email, formData.avatar]);

  // Update form data field
  const updateField = useCallback(<K extends keyof FormData>(field: K, value: FormData[K]) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  }, []);

  // Navigate to next step
  const goNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !formData.role) return;
    if (currentStep < 3) setCurrentStep((prev) => (prev + 1) as Step);
  }, [currentStep, isStep1Valid, formData.role]);

  // Navigate to previous step
  const goBack = useCallback(() => {
    if (currentStep > 1) setCurrentStep((prev) => (prev - 1) as Step);
  }, [currentStep]);

  // Submit the form
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // Submit the form
  const handleSubmit = useCallback(() => {
    complete(formData);
  }, [formData, complete]);
  return { currentStep, formData, isStep1Valid, updateField, goNext, goBack, handleSubmit };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const { currentStep, formData, isStep1Valid, updateField, goNext, goBack, handleSubmit } = state;

  const progressPercent = (currentStep / 3) * 100;

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* STEP INDICATOR */}
        <Stack gap={8}>
          <Stack direction="horizontal" align="center" justify="between">
            <Heading level={2}>Setup Your Profile</Heading>
            <Badge variant="primary">{currentStep} of 3</Badge>
          </Stack>
          <Progress value={progressPercent} max={100} size="md" />
        </Stack>

        {/* CONTENT */}
        <Card shadow="md" padding={24}>
          {/* STEP 1: Profile Setup */}
          {currentStep === 1 && (
            <Stack gap={16}>
              <Heading level={3}>Profile Information</Heading>
              <Input
                label="Full Name"
                placeholder="Enter your name"
                value={formData.name}
                onChange={(value) => updateField('name', value)}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(value) => updateField('email', value)}
                error={formData.email && !isValidEmail(formData.email) ? 'Invalid email format' : ''}
                required
              />
              <Stack gap={8}>
                <Text variant="label">Avatar</Text>
                <Row gap={8}>
                   {(props.avatarOptions || []).map((emoji) => (
                    <Box
                      key={emoji}
                      as={Clickable}
                      onClick={() => updateField('avatar', emoji)}
                      padding={8}
                      borderRadius={8}
                      background={formData.avatar === emoji ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'transparent'}
                      style={{ border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outline, #d4d4d8)', cursor: 'pointer', transition: 'all 200ms ease' }}
                    >
                      <Text size="2xl">{emoji}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          )}

          {/* STEP 2: Preferences */}
          {currentStep === 2 && (
            <Stack gap={16}>
              <Heading level={3}>Preferences</Heading>
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => updateField('role', value)}
                 options={(props.roleOptions || []).map((role) => ({ value: role, label: role }))}
              />
              <Toggle
                label="Enable Email Notifications"
                checked={formData.emailNotifications}
                onChange={(checked) => updateField('emailNotifications', checked)}
                size="md"
              />
              <Toggle
                label={`Theme: ${formData.theme === 'light' ? 'Light' : 'Dark'}`}
                checked={formData.theme === 'dark'}
                onChange={(checked) => updateField('theme', checked ? 'dark' : 'light')}
                size="md"
              />
            </Stack>
          )}

          {/* STEP 3: Review & Confirm */}
          {currentStep === 3 && (
            <Stack gap={16}>
              <Heading level={3}>Review Your Setup</Heading>
               <Box gap={12} padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                 <Stack gap={4}>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                   <Text>{formData.name}</Text>
                 </Stack>
                 <Divider />
                 <Stack gap={4}>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                   <Text>{formData.email}</Text>
                 </Stack>
                 <Divider />
                 <Stack gap={4}>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
                   <Text size="xl">{formData.avatar}</Text>
                 </Stack>
                 <Divider />
                 <Stack gap={4}>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                   <Text>{formData.role}</Text>
                 </Stack>
                 <Divider />
                 <Stack gap={4}>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
                   <Text>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                 </Stack>
                 <Divider />
                 <Stack gap={4}>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                   <Text>{formData.theme === 'light' ? 'Light' : 'Dark'}</Text>
                 </Stack>
               </Box>
            </Stack>
          )}
        </Card>

        {/* NAVIGATION */}
        <Row gap={8} justify="between">
          <Button
            variant="ghost"
            onClick={goBack}
            disabled={currentStep === 1}
          >
            Go Back
          </Button>
           {currentStep < 3 && (
             <Button
               variant="primary"
               onClick={goNext}
               disabled={(currentStep === 1 && !isStep1Valid) || (currentStep === 2 && !formData.role)}
             >
               Next
             </Button>
          )}
          {currentStep === 3 && (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
